import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import CertificateGenerator from '../../services/CertificateGenerator'; // Adjusted path
import LoadingSpinner from '../shared/LoadingSpinner';
import AlertMessage from '../shared/AlertMessage';

const CertificateViewerPage = () => {
  const { certificateId, templateName } = useParams();
  const [certificateSvgUrl, setCertificateSvgUrl] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadCertificate = async () => {
      setLoading(true);
      setError(null);
      try {
        // 1. Fetch certificate data (basic structure, adapt as needed)
        // This assumes you have an API endpoint to get raw certificate data by ID
        // You might need to pass a token if your API requires authentication
        const token = localStorage.getItem('auth_token');
        const response = await fetch(`/api/certificates/${certificateId}`, {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });

        if (!response.ok) {
          const errData = await response.json();
          throw new Error(
            errData.message || `Failed to fetch certificate data: ${response.statusText}`
          );
        }
        const certDataResponse = await response.json();
        const certificateData = certDataResponse.data;

        if (!certificateData) {
          throw new Error('Certificate data not found in API response.');
        }

        // Add templatePath if a specific template is requested via URL
        // (previewCertificate uses templatePath or defaults to simple-modern-certificate.svg)
        if (templateName) {
          certificateData.templatePath = `/images/${templateName}.svg`;
        } else {
          // Ensure a default if not specified, though previewCertificate has its own default
          certificateData.templatePath = '/images/simple-modern-certificate.svg';
        }

        // 2. Generate SVG URL using CertificateGenerator
        const svgUrl = await CertificateGenerator.previewCertificate(certificateData);
        setCertificateSvgUrl(svgUrl);
      } catch (err) {
        console.error('Error loading certificate for viewer:', err);
        setError(err.message || 'Could not load certificate.');
        // Optionally, set a placeholder/error SVG URL
        setCertificateSvgUrl(
          CertificateGenerator.generateErrorImage({
            certificateId,
            name: 'Error',
            course: 'N/A',
            date: new Date().toISOString(),
          })
        );
      } finally {
        setLoading(false);
      }
    };

    if (certificateId) {
      loadCertificate();
    } else {
      setError('Certificate ID is missing.');
      setLoading(false);
    }

    // Cleanup function for the blob URL
    return () => {
      if (certificateSvgUrl && certificateSvgUrl.startsWith('blob:')) {
        URL.revokeObjectURL(certificateSvgUrl);
      }
    };
  }, [certificateId, templateName]); // REMOVED certificateSvgUrl from dependencies

  if (loading) {
    return (
      <div
        style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100vh' }}
      >
        <LoadingSpinner message="Loading certificate..." />
      </div>
    );
  }

  if (error) {
    return (
      <div style={{ padding: '20px' }}>
        <AlertMessage type="error" message={{ title: 'Error', details: error }} />
      </div>
    );
  }

  if (!certificateSvgUrl) {
    return (
      <div style={{ padding: '20px' }}>
        <AlertMessage
          type="warning"
          message={{
            title: 'Certificate Not Available',
            details: 'The certificate image could not be generated.',
          }}
        />
      </div>
    );
  }

  // Render just the image. Ensure the page has minimal styling.
  // The SVG itself should define its dimensions.
  return (
    <div
      style={{
        margin: 0,
        padding: 0,
        width: '100vw',
        height: '100vh',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        backgroundColor: '#525659' /* Optional: a background for the page itself */,
      }}
    >
      <img
        src={certificateSvgUrl}
        alt={`Certificate ${certificateId}`}
        style={{ maxWidth: '100%', maxHeight: '100%', objectFit: 'contain' }}
      />
    </div>
  );
};

export default CertificateViewerPage;
